SELECT c.id, c.competition_id as competitionId, c.create_time as createTime, comp.name as competitionName, comp.date as deadline, '进行中' as status FROM care c LEFT JOIN competition comp ON c.competition_id = comp.id
AND c.user_id = #{userId}
ORDER BY c.create_time DESC
